export const getGetBuildingUnitsUrl = (buildingId: string,
    params?: GetBuildingUnitsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/buildings/${buildingId}/units?${stringifiedParams}` : `/api/buildings/${buildingId}/units`
}

